SELECT supplier_id, name AS supplier_name, contact_name, phone, email, address, payment_terms, lead_time_days, is_active FROM suppliers
AND (name LIKE '%' + #{search} + '%' OR contact_name LIKE '%' + #{search} + '%' OR phone LIKE '%' + #{search} + '%') AND is_active = #{isActive}
ORDER BY name OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY
